import{_ as a,c as n,o as t,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Démarrage rapide : Maîtrisez Plannotator en 5 minutes","description":"Apprenez à installer et configurer Plannotator. Installez le CLI en 5 minutes, configurez le plugin Claude Code ou OpenCode, et maîtrisez la revue de plans et de code.","frontmatter":{"title":"Démarrage rapide : Maîtrisez Plannotator en 5 minutes","sidebarTitle":"Démarrage en 5 min","subtitle":"Démarrage rapide : Maîtrisez Plannotator en 5 minutes","description":"Apprenez à installer et configurer Plannotator. Installez le CLI en 5 minutes, configurez le plugin Claude Code ou OpenCode, et maîtrisez la revue de plans et de code.","tags":["Démarrage rapide","Introduction","Installation","Claude Code","OpenCode"],"order":1},"headers":[],"relativePath":"fr/backnotprop/plannotator/start/getting-started/index.md","filePath":"fr/backnotprop/plannotator/start/getting-started/index.md"}'),i={name:"fr/backnotprop/plannotator/start/getting-started/index.md"};function o(l,e,r,p,d,u){return t(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="demarrage-rapide-maitrisez-plannotator-en-5-minutes" tabindex="-1">Démarrage rapide : Maîtrisez Plannotator en 5 minutes <a class="header-anchor" href="#demarrage-rapide-maitrisez-plannotator-en-5-minutes" aria-label="Permalink to &quot;Démarrage rapide : Maîtrisez Plannotator en 5 minutes&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que vous apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que vous apprendrez&quot;">​</a></h2><ul><li>✅ Comprendre les fonctionnalités principales et les cas d&#39;usage de Plannotator</li><li>✅ Installer Plannotator en 5 minutes</li><li>✅ Configurer l&#39;intégration avec Claude Code ou OpenCode</li><li>✅ Effectuer votre première revue de plan et de code</li></ul><h2 id="les-problemes-que-vous-rencontrez" tabindex="-1">Les problèmes que vous rencontrez <a class="header-anchor" href="#les-problemes-que-vous-rencontrez" aria-label="Permalink to &quot;Les problèmes que vous rencontrez&quot;">​</a></h2><p><strong>Plannotator</strong> est un outil de revue interactif conçu pour Claude Code et OpenCode, qui résout les problèmes suivants :</p><p><strong>Problème 1</strong> : Les plans d&#39;implémentation générés par l&#39;IA sont difficiles à lire dans le terminal — trop de texte, structure peu claire, revue fatigante.</p><p><strong>Problème 2</strong> : Pour donner un retour à l&#39;IA, vous devez décrire textuellement « supprimer le 3e paragraphe », « modifier cette fonction » — coût de communication élevé.</p><p><strong>Problème 3</strong> : Lors de la revue de code, vous devez jongler entre plusieurs terminaux ou IDE, difficile de rester concentré.</p><p><strong>Problème 4</strong> : Les membres de l&#39;équipe veulent participer à la revue, mais ne savent pas comment partager le contenu du plan.</p><p><strong>Plannotator vous aide à</strong> :</p><ul><li>Remplacer la lecture en terminal par une interface visuelle claire et structurée</li><li>Sélectionner du texte pour ajouter des annotations (supprimer, remplacer, commenter) — retour précis</li><li>Revue visuelle des diff Git avec annotations ligne par ligne</li><li>Partage par URL, collaboration d&#39;équipe sans backend</li></ul><h2 id="quand-utiliser-cet-outil" tabindex="-1">Quand utiliser cet outil <a class="header-anchor" href="#quand-utiliser-cet-outil" aria-label="Permalink to &quot;Quand utiliser cet outil&quot;">​</a></h2><p><strong>Cas d&#39;usage</strong> :</p><ul><li>Développement assisté par IA avec Claude Code ou OpenCode</li><li>Revue des plans d&#39;implémentation générés par l&#39;IA</li><li>Examen des modifications de code</li><li>Partage des résultats de revue de plan ou de code avec l&#39;équipe</li></ul><p><strong>Cas non adaptés</strong> :</p><ul><li>Code écrit entièrement à la main (sans plans générés par l&#39;IA)</li><li>Processus de revue de code déjà en place (comme les PR GitHub)</li><li>Pas besoin d&#39;outil de revue visuelle</li></ul><h2 id="concept-principal" tabindex="-1">Concept principal <a class="header-anchor" href="#concept-principal" aria-label="Permalink to &quot;Concept principal&quot;">​</a></h2><h3 id="qu-est-ce-que-plannotator" tabindex="-1">Qu&#39;est-ce que Plannotator <a class="header-anchor" href="#qu-est-ce-que-plannotator" aria-label="Permalink to &quot;Qu&#39;est-ce que Plannotator&quot;">​</a></h3><p><strong>Plannotator</strong> est un outil de revue interactif conçu pour les AI Coding Agents (Claude Code, OpenCode), offrant deux fonctionnalités principales :</p><ol><li><strong>Revue de plan</strong> : Revue visuelle des plans d&#39;implémentation générés par l&#39;IA, avec support des annotations, approbation ou rejet</li><li><strong>Revue de code</strong> : Revue visuelle des diff Git, avec annotations ligne par ligne et plusieurs modes d&#39;affichage</li></ol><h3 id="fonctionnement" tabindex="-1">Fonctionnement <a class="header-anchor" href="#fonctionnement" aria-label="Permalink to &quot;Fonctionnement&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  AI Agent      │</span></span>
<span class="line"><span>│  (génère plan) │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Plannotator   │  ← Serveur HTTP local</span></span>
<span class="line"><span>│  (interface)   │</span></span>
<span class="line"><span>└────────┬────────┘</span></span>
<span class="line"><span>         │</span></span>
<span class="line"><span>         ▼</span></span>
<span class="line"><span>┌─────────────────┐</span></span>
<span class="line"><span>│  Navigateur    │</span></span>
<span class="line"><span>│  (revue user)  │</span></span>
<span class="line"><span>└─────────────────┘</span></span></code></pre></div><p><strong>Flux principal</strong> :</p><ol><li>L&#39;AI Agent termine un plan ou des modifications de code</li><li>Plannotator démarre un serveur HTTP local et ouvre le navigateur</li><li>L&#39;utilisateur consulte le plan/code dans le navigateur et ajoute des annotations</li><li>L&#39;utilisateur approuve ou rejette, Plannotator renvoie la décision à l&#39;AI Agent</li><li>L&#39;AI Agent continue l&#39;implémentation ou modifie selon le retour</li></ol><h3 id="securite" tabindex="-1">Sécurité <a class="header-anchor" href="#securite" aria-label="Permalink to &quot;Sécurité&quot;">​</a></h3><p><strong>Toutes les données sont traitées localement</strong>, rien n&#39;est envoyé dans le cloud :</p><ul><li>Le contenu du plan, les diff de code et les annotations sont stockés sur votre machine locale</li><li>Le serveur HTTP local utilise un port aléatoire (ou fixe)</li><li>Le partage par URL fonctionne en compressant les données dans le hash de l&#39;URL, sans backend</li></ul><h2 id="🎒-prerequis" tabindex="-1">🎒 Prérequis <a class="header-anchor" href="#🎒-prerequis" aria-label="Permalink to &quot;🎒 Prérequis&quot;">​</a></h2><p><strong>Configuration requise</strong> :</p><ul><li>Système d&#39;exploitation : macOS / Linux / Windows / WSL</li><li>Runtime : Bun (le script d&#39;installation s&#39;en charge automatiquement)</li><li>Environnement IA : Claude Code 2.1.7+ ou OpenCode</li></ul><p><strong>Choix du mode d&#39;installation</strong> :</p><ul><li>Si vous utilisez Claude Code : installez CLI + plugin</li><li>Si vous utilisez OpenCode : configurez le plugin</li><li>Pour la revue de code uniquement : installez seulement le CLI</li></ul><h2 id="suivez-le-guide" tabindex="-1">Suivez le guide <a class="header-anchor" href="#suivez-le-guide" aria-label="Permalink to &quot;Suivez le guide&quot;">​</a></h2><h3 id="etape-1-installer-le-cli-plannotator" tabindex="-1">Étape 1 : Installer le CLI Plannotator <a class="header-anchor" href="#etape-1-installer-le-cli-plannotator" aria-label="Permalink to &quot;Étape 1 : Installer le CLI Plannotator&quot;">​</a></h3><p><strong>macOS / Linux / WSL</strong> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://plannotator.ai/install.sh</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> bash</span></span></code></pre></div><p><strong>Windows PowerShell</strong> :</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">irm https:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">plannotator.ai</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">install.ps1 </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> iex</span></span></code></pre></div><p><strong>Windows CMD</strong> :</p><div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsSL https://plannotator.ai/install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">o install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> install.cmd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> del install.cmd</span></span></code></pre></div><p><strong>Résultat attendu</strong> : Le script d&#39;installation télécharge automatiquement le CLI Plannotator, l&#39;ajoute au PATH système et affiche le numéro de version (ex : &quot;plannotator v0.6.7 installed to ...&quot;).</p><div class="tip custom-block"><p class="custom-block-title">Que fait le script d&#39;installation ?</p><p>Le script d&#39;installation :</p><ol><li>Télécharge la dernière version du CLI Plannotator</li><li>L&#39;ajoute au PATH système</li><li>Nettoie les anciennes versions éventuelles</li><li>Installe automatiquement la commande <code>/plannotator-review</code> (pour la revue de code)</li></ol></div><h3 id="etape-2-configurer-claude-code-optionnel" tabindex="-1">Étape 2 : Configurer Claude Code (optionnel) <a class="header-anchor" href="#etape-2-configurer-claude-code-optionnel" aria-label="Permalink to &quot;Étape 2 : Configurer Claude Code (optionnel)&quot;">​</a></h3><p>Si vous utilisez Claude Code, vous devez installer le plugin.</p><p><strong>Exécutez dans Claude Code</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/plugin marketplace add backnotprop/plannotator</span></span>
<span class="line"><span>/plugin install plannotator@plannotator</span></span></code></pre></div><p><strong>Important</strong> : Après l&#39;installation du plugin, <strong>vous devez redémarrer Claude Code</strong> pour que le hook prenne effet.</p><p><strong>Résultat attendu</strong> : Après une installation réussie, <code>plannotator</code> apparaît dans la liste des plugins de Claude Code.</p><div class="info custom-block"><p class="custom-block-title">Configuration manuelle (optionnel)</p><p>Si vous ne souhaitez pas utiliser le système de plugins, vous pouvez configurer le hook manuellement. Voir la section <a href="./../installation-claude-code/">Installation du plugin Claude Code</a>.</p></div><h3 id="etape-3-configurer-opencode-optionnel" tabindex="-1">Étape 3 : Configurer OpenCode (optionnel) <a class="header-anchor" href="#etape-3-configurer-opencode-optionnel" aria-label="Permalink to &quot;Étape 3 : Configurer OpenCode (optionnel)&quot;">​</a></h3><p>Si vous utilisez OpenCode, vous devez modifier le fichier <code>opencode.json</code>.</p><p><strong>Modifiez <code>opencode.json</code></strong> :</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;$schema&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://opencode.ai/config.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;plugin&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;@plannotator/opencode@latest&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong>Redémarrez OpenCode</strong>.</p><p><strong>Résultat attendu</strong> : Après le redémarrage, OpenCode charge automatiquement le plugin et l&#39;outil <code>submit_plan</code> devient disponible.</p><h3 id="etape-4-premiere-revue-de-plan-exemple-claude-code" tabindex="-1">Étape 4 : Première revue de plan (exemple Claude Code) <a class="header-anchor" href="#etape-4-premiere-revue-de-plan-exemple-claude-code" aria-label="Permalink to &quot;Étape 4 : Première revue de plan (exemple Claude Code)&quot;">​</a></h3><p><strong>Condition de déclenchement</strong> : Demandez à Claude Code de générer un plan d&#39;implémentation et d&#39;appeler <code>ExitPlanMode</code>.</p><p><strong>Exemple de conversation</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utilisateur : Crée-moi un plan d&#39;implémentation pour un module d&#39;authentification utilisateur</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Claude : D&#39;accord, voici le plan d&#39;implémentation :</span></span>
<span class="line"><span>1. Créer le modèle utilisateur</span></span>
<span class="line"><span>2. Implémenter l&#39;API d&#39;inscription</span></span>
<span class="line"><span>3. Implémenter l&#39;API de connexion</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(appelle ExitPlanMode)</span></span></code></pre></div><p><strong>Résultat attendu</strong> :</p><ol><li>Le navigateur ouvre automatiquement l&#39;interface Plannotator</li><li>Affiche le contenu du plan généré par l&#39;IA</li><li>Vous pouvez sélectionner du texte du plan et ajouter des annotations (supprimer, remplacer, commenter)</li><li>En bas, les boutons &quot;Approve&quot; et &quot;Request Changes&quot;</li></ol><p><strong>Actions</strong> :</p><ol><li>Consultez le plan dans le navigateur</li><li>Si le plan est correct, cliquez sur <strong>Approve</strong> → L&#39;IA continue l&#39;implémentation</li><li>Si des modifications sont nécessaires, sélectionnez le texte à modifier, cliquez sur <strong>Delete</strong>, <strong>Replace</strong> ou <strong>Comment</strong> → Cliquez sur <strong>Request Changes</strong></li></ol><p><strong>Résultat attendu</strong> : Après le clic, le navigateur se ferme automatiquement, Claude Code reçoit votre décision et continue l&#39;exécution.</p><h3 id="etape-5-premiere-revue-de-code" tabindex="-1">Étape 5 : Première revue de code <a class="header-anchor" href="#etape-5-premiere-revue-de-code" aria-label="Permalink to &quot;Étape 5 : Première revue de code&quot;">​</a></h3><p><strong>Exécutez dans le répertoire du projet</strong> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>Résultat attendu</strong> :</p><ol><li>Le navigateur ouvre la page de revue de code</li><li>Affiche le diff Git (par défaut, les modifications non commitées)</li><li>À gauche l&#39;arborescence des fichiers, à droite le visualiseur de diff</li><li>Cliquez sur les numéros de ligne pour sélectionner une plage de code et ajouter des annotations</li></ol><p><strong>Actions</strong> :</p><ol><li>Parcourez les modifications de code dans le visualiseur de diff</li><li>Cliquez sur les numéros de ligne pour sélectionner le code à réviser</li><li>Ajoutez des annotations dans le panneau de droite (comment/suggestion/concern)</li><li>Cliquez sur <strong>Send Feedback</strong> pour envoyer à l&#39;agent, ou cliquez sur <strong>LGTM</strong> pour approuver</li></ol><p><strong>Résultat attendu</strong> : Après avoir cliqué sur Send Feedback, le navigateur se ferme, le terminal affiche le retour formaté, et l&#39;agent le traite automatiquement.</p><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Après avoir terminé les étapes ci-dessus, vous devriez pouvoir :</p><ul><li>[ ] Le script d&#39;installation affiche &quot;plannotator vX.X.X installed to ...&quot;</li><li>[ ] Déclencher la revue de plan dans Claude Code, le navigateur ouvre automatiquement l&#39;interface</li><li>[ ] Sélectionner du texte du plan dans l&#39;interface et ajouter des annotations</li><li>[ ] Cliquer sur Approve ou Request Changes et voir le navigateur se fermer</li><li>[ ] Exécuter <code>/plannotator-review</code> et voir l&#39;interface de revue de code</li><li>[ ] Ajouter des annotations ligne par ligne dans la revue de code et cliquer sur Send Feedback</li></ul><p><strong>Si une étape échoue</strong>, consultez :</p><ul><li><a href="./../installation-claude-code/">Guide d&#39;installation Claude Code</a></li><li><a href="./../installation-opencode/">Guide d&#39;installation OpenCode</a></li><li><a href="./../../faq/common-problems/">Questions fréquentes</a></li></ul><h2 id="pieges-a-eviter" tabindex="-1">Pièges à éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à éviter&quot;">​</a></h2><p><strong>Erreur courante 1</strong> : Après l&#39;installation, <code>plannotator</code> affiche &quot;command not found&quot;</p><p><strong>Cause</strong> : La variable d&#39;environnement PATH n&#39;est pas mise à jour, ou le terminal doit être redémarré.</p><p><strong>Solution</strong> :</p><ul><li>macOS/Linux : Exécutez <code>source ~/.zshrc</code> ou <code>source ~/.bashrc</code>, ou redémarrez le terminal</li><li>Windows : Redémarrez PowerShell ou CMD</li></ul><p><strong>Erreur courante 2</strong> : Après l&#39;installation du plugin Claude Code, la revue de plan ne se déclenche pas</p><p><strong>Cause</strong> : Claude Code n&#39;a pas été redémarré, le hook n&#39;est pas actif.</p><p><strong>Solution</strong> : Quittez complètement Claude Code (pas seulement fermer la fenêtre), puis rouvrez-le.</p><p><strong>Erreur courante 3</strong> : Le navigateur ne s&#39;ouvre pas automatiquement</p><p><strong>Cause</strong> : Peut-être en mode distant (devcontainer, SSH), ou le port est occupé.</p><p><strong>Solution</strong> :</p><ul><li>Vérifiez si la variable d&#39;environnement <code>PLANNOTATOR_REMOTE=1</code> est définie</li><li>Consultez l&#39;URL affichée dans le terminal et ouvrez-la manuellement dans le navigateur</li><li>Voir <a href="./../../advanced/remote-mode/">Mode distant/Devcontainer</a></li></ul><p><strong>Erreur courante 4</strong> : La revue de code affiche &quot;No changes&quot;</p><p><strong>Cause</strong> : Aucune modification git non commitée actuellement.</p><p><strong>Solution</strong> :</p><ul><li>Exécutez d&#39;abord <code>git status</code> pour confirmer qu&#39;il y a des modifications</li><li>Ou exécutez <code>git add</code> pour indexer quelques fichiers</li><li>Ou passez à un autre type de diff (comme last commit)</li></ul><h2 id="resume" tabindex="-1">Résumé <a class="header-anchor" href="#resume" aria-label="Permalink to &quot;Résumé&quot;">​</a></h2><p>Plannotator est un outil de revue local qui améliore l&#39;efficacité de la revue de plans et de code grâce à une interface visuelle :</p><p><strong>Fonctionnalités principales</strong> :</p><ul><li><strong>Revue de plan</strong> : Revue visuelle des plans générés par l&#39;IA avec annotations précises</li><li><strong>Revue de code</strong> : Revue visuelle des diff Git avec annotations ligne par ligne</li><li><strong>Partage par URL</strong> : Partage du contenu de revue sans backend</li><li><strong>Intégrations tierces</strong> : Sauvegarde automatique des plans approuvés vers Obsidian/Bear</li></ul><p><strong>Avantages clés</strong> :</p><ul><li>Exécution locale, données sécurisées</li><li>Interface visuelle, efficacité accrue</li><li>Retour précis, coût de communication réduit</li><li>Collaboration d&#39;équipe, sans système de comptes</li></ul><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons <strong><a href="./../installation-claude-code/">Installation du plugin Claude Code</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Les étapes détaillées d&#39;installation du plugin Claude Code</li><li>Comment configurer manuellement le hook</li><li>Comment vérifier que l&#39;installation a réussi</li><li>Les solutions aux problèmes d&#39;installation courants</li></ul></blockquote><hr><h2 id="annexe-references-du-code-source" tabindex="-1">Annexe : Références du code source <a class="header-anchor" href="#annexe-references-du-code-source" aria-label="Permalink to &quot;Annexe : Références du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Point d&#39;entrée CLI (revue de plan)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L1-L50" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>1-50</td></tr><tr><td>Point d&#39;entrée CLI (revue de code)</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/apps/hook/server/index.ts#L46-L84" target="_blank" rel="noreferrer"><code>apps/hook/server/index.ts</code></a></td><td>46-84</td></tr><tr><td>Serveur de revue de plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L1-L200" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>1-200</td></tr><tr><td>Serveur de revue de code</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/review.ts#L1-L150" target="_blank" rel="noreferrer"><code>packages/server/review.ts</code></a></td><td>1-150</td></tr><tr><td>Utilitaires Git</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L1-L100" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>1-100</td></tr><tr><td>Interface de revue de plan</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>1-200</td></tr><tr><td>Interface de revue de code</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L1-L200" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>1-200</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>MAX_RETRIES = 5</code> : Nombre de tentatives de port (<code>packages/server/index.ts:80</code>)</li><li><code>RETRY_DELAY_MS = 500</code> : Délai entre les tentatives (<code>packages/server/index.ts:80</code>)</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>startPlannotatorServer()</code> : Démarre le serveur de revue de plan (<code>packages/server/index.ts</code>)</li><li><code>startReviewServer()</code> : Démarre le serveur de revue de code (<code>packages/server/review.ts</code>)</li><li><code>runGitDiff()</code> : Exécute la commande git diff (<code>packages/server/git.ts</code>)</li></ul><p><strong>Variables d&#39;environnement</strong> :</p><ul><li><code>PLANNOTATOR_REMOTE</code> : Indicateur de mode distant (<code>apps/hook/server/index.ts:17</code>)</li><li><code>PLANNOTATOR_PORT</code> : Port fixe (<code>apps/hook/server/index.ts:18</code>)</li><li><code>PLANNOTATOR_BROWSER</code> : Navigateur personnalisé (<code>apps/hook/README.md:79</code>)</li><li><code>PLANNOTATOR_SHARE</code> : Activation du partage par URL (<code>apps/hook/server/index.ts:44</code>)</li></ul></details>`,104)])])}const h=a(i,[["render",o]]);export{g as __pageData,h as default};
